def extract_docstring(source):
    lines = source.split('\n')
    in_multi_comment = False
    for line in lines:
        stripped = line.strip()
        if stripped.startswith('"""') or stripped.startswith("'''"):
            if not in_multi_comment:
                # Start of a multi-line string/comment
                if stripped.count('"""') == 2 or stripped.count("'''") == 2:
                    # It's a one-liner, check if it's after def
                    prev_lines = '\n'.join(lines[:lines.index(line)])
                    if 'def ' in prev_lines:
                        return stripped[3:-3]
                else:
                    in_multi_comment = True
            else:
                in_multi_comment = False
        elif in_multi_comment:
            continue
        elif stripped.startswith('def '):
            # Look for docstring in next non-empty, non-comment line
            idx = lines.index(line) + 1
            while idx < len(lines):
                next_line = lines[idx].strip()
                if next_line.startswith('#'):
                    idx += 1
                    continue
                if next_line.startswith('"""') or next_line.startswith("'''"):
                    if next_line.count('"""') == 2 or next_line.count("'''") == 2:
                        return next_line[3:-3]
                    else:
                        # Multi-line docstring
                        doc_lines = [next_line[3:]]
                        idx += 1
                        while idx < len(lines):
                            inner = lines[idx].strip()
                            if inner.endswith('"""') or inner.endswith("'''"):
                                doc_lines.append(inner[:-3])
                                return '\n'.join(doc_lines)
                            else:
                                doc_lines.append(inner)
                            idx += 1
                break
    return "None"

